import{_ as p,o as b,c as e,j as r,a as o,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const k=JSON.parse('{"title":"黑靴(Dark Boots)","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/黑靴(Dark Boots).md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/黑靴(Dark Boots).md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/黑靴(Dark Boots).md"};function n(d,a,c,_,i,l){return b(),e("div",null,[...a[0]||(a[0]=[r("h1",{id:"黑靴-dark-boots",tabindex:"-1"},[o("黑靴(Dark Boots) "),r("a",{class:"header-anchor",href:"#黑靴-dark-boots","aria-label":'Permalink to "黑靴(Dark Boots)"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),t('<h1 id="黑靴-dark-boots-1" tabindex="-1">黑靴(Dark Boots) <a class="header-anchor" href="#黑靴-dark-boots-1" aria-label="Permalink to &quot;黑靴(Dark Boots)&quot;">​</a></h1><p>黑靴(Dark Boots)<br> 本质：魔幻本质<br> 价格：D+500<br> 分类：鞋<br> 描述：装备型的对恶魔武器，是可以随主人心意而变成任何造型的靴子，未来对抗恶魔而开发出的圣洁武器，与其他装备型圣器不同的是，innocence可以进化成结晶型。<br> 你需要通过逐级购买来提升解放形态，并且自己练习如何解放它的力量。</p><p>第一解放：消耗一个迅捷动作与1点意志力，你使长靴在本场景内进入第一解放状态，处于解放状态下你才会获得该装备提供的所有好处。</p><p>凌冽蹴击：在你以双脚天生武器进行的攻击中提供2点附加成功，若你的天生武器没有伤害，则转变为提供3L武器伤害与1点附加成功。<br> 当你位于空中对其他目标进行冲锋，并且使用双脚进行攻击时，你每移动1米，则攻击检定额外获得1DP环境加值，该加值不得超过你的敏捷值/2点。</p><p>花费：C+1000<br> 购买本等级会替换上个等级的效果，但价格依旧是逐级购买。<br> 第二解放：现在你可以在进入第一解放状态时宣言进入第二解放“系累”状态，并且获得一成同步境界。这会使进入第一解放状态的动作提升至移动动作，持续时间不会改变，意志力消耗改为无需消耗。</p><p>轻盈身躯：你的决心贯彻在圣器之中，靴子膝部浮现出青色的魔力花纹，使你的身体更加迅捷而精准。<br> 你在基础防御上获得1DP加值，在基础移动速度获得10米的提升。</p><p>凌冽蹴击：在你以双脚天生武器进行的攻击中提供4点附加成功与2L武器伤害，若你的天生武器没有伤害，则转变为提供5L武器伤害与3点附加成功。<br> 当你位于空中对其他目标进行冲锋，并且使用双脚进行攻击时，你每移动1米，则攻击检定额外获得1DP环境加值，该加值不得超过你的敏捷值/2点。</p><p>踏空飞行：你可以获得普通机动性的飞行能力，速度等于你的基础移动速度。</p><p>圣洁武器：穿戴者以脚作为天生武器对黑暗生物造成伤害时，可以将其中1点严重伤害转为韧性伤害。</p><p>境界提升：<br> 你现在可以用经验值或支线与分数提升同步境界，境界提升等同于购买了逐级提升的武器。提升境界带来的能力和加值只有第二解放状态下有效。</p><p>境界提升后，武器的基础性能也会获得增强，在3/5/7/10成境界时，分别使武器伤害提升3/8/7/12L。</p><p>升级（10XP/D+500）：<br> 三成境界：以一成境界开始计算，每提升两成境界，则“轻盈身躯”所带来的基础移动速度就再增加5米，基础防御再增加1点。</p><p>升级（20XP/C+1000）：<br> 五成境界：从一成境界开始计算，每提升两成境界，则飞行能力机动性提升1级（机动性上限：完美）。若因此提升到完美，在接下来机动性提升时，获得空中冲锋不承受减值的效果。</p><p>升级（43XP/B+3000）：<br> 七成境界：“除魔圣器”所带来针对黑暗生物1点严重伤害转为韧性的效果，改为：在攻击黑暗生物时，获得【幻灭】特性。<br> 除此之外，你在以该武器进行攻击时，获得等同于自身内在支线*2点防御忽略能力，若计算破防能力后这个效果将防御完全忽略，则将剩余的忽略数值转为攻击上的器械加值。<br> 仅限于针对无名类型防御时，这个数值再*4倍计算。</p><p>升级：（80XP/A+4000）<br> 十成境界：武器会永久性进入特殊状态“结晶”。<br> 特殊状态“结晶”<br> 将黑靴的Innocence还原为最初状态，以液化的方式喝下。如果这样做，它会在你的脚踝上刻下深深的圣痕，从伤口中混杂着你的血液流出，然后重新形成新的形态，从装备型的Innocence变为结晶形态，外形变得更加优雅，洗炼，如黑色金属打造而成，脚根出现小型的黑色蝴蝶般的飞翼。在此状态下，你的能力会焕然一新，获得全面的提升。在它不发动的时候，会变成漂亮的红色脚环，套在脚踝上。</p><p>限界解放：当你处于十成境界的状态下，将第二解放动作降低至一个自由动作，随后可以选择立刻进入限界解放状态，该武器将获得以下效果。</p><p>愈加轻灵：你免疫不超过A级的定身效果，除此之外，你在敏捷相关检定上获得6DP的器械加值。</p><p>攻防一体：“凌冽蹴击”增加“当你进行肉搏格挡时，你额外获得自身传奇决心*2点格挡防御，以及传奇敏捷*1点全伤害吸收”的效果。</p><p>无限增速：每轮开始时，你获得一层【破限】，每层【破限】会使你的基础移动速度增加传奇决心*20米，同时在攻击和闪避防御上获得传奇决心*1点速度加值，【破限】层数的上限等同你的决心/层。<br> 你可以选择获得超过决心/层的【破限】，但每超过传奇决心/层，就要在持续时间内每轮承受1点韧性伤害，叠加计算，此时你的肌肤上浮现出许多六角形的纹路，这些纹路会越来越多，直到爬满你的全身。</p><p>相关招式<br> 以下几个能力，都是长靴本身具有的，但你需要经过锻炼或购买，才能熟练运用它们，使用的前提是最少拥有一成同步境界。</p><p>圆舞·雾风<br> 价格：C+1000<br> 动作：整轮动作<br> 类型：攻击技<br> 消耗：2点通用能量/1意志力<br> 射程：见下<br> 范围：见下<br> 描述：以踢击形成如龙卷风般的攻击<br> 效果：<br> 消费一个整轮动作，你在空中进行一次冲锋攻击，本次冲锋攻击会在这次冲锋中形成巨大的龙卷风，它会随着你的移动而移动，等同于你对冲锋路径上的敌对目标进行一次攻击。<br> 对方不进行正常防御，而是以反射豁免对抗攻击成功数。如果没有完全将伤害豁免，则使其这次豁免结果的成功数减少你的传奇敏捷*1.5点，小数忽略。</p><p>水上之踏技·水枷<br> 价格：D+500/C+1000<br> 分类：被动<br> 描述：能立足水面上战斗的能力，即使用在其他地方也能提高使用者的灵活度，甚至连身形都不会被捕捉到。<br> 效果：根据开发方向决定价格及效果，可以支付价格购买其他方向的开发。</p><p>灵活D：你获得水上行走能力，以及C级困难地形的免疫效果。<br> 高速C：“你看到的，不过是我的残影。”<br> 你在每次移动后获得C级自然本质的反侦测能力，持续一轮。</p><p>音响之踏技·音枷<br> 价格：B+2000<br> 类型：被动<br> 描述：以声音产生的空气波动为基础，产生如音速的移动……不过，因为过快的速度也会导致自身无法控制，在战斗中使用这个效果和自杀也没什么区别。<br> 效果：购买后，你每回合获得一个额外只能进行移动的移动动作。<br> 除此之外，你视为具有【B级旅行速度】。使用旅行速度需要你在十个回合中投入所有AP，全神贯注的与空气波动同调，在这期间失去基础和闪避防御，一旦受到伤害则立刻重新同调，且受到攻击时还需要进行DC等于伤害数的反射检定，否则对方可以选择执行致命一击，让攻击DP将全部取10计算。</p><p>只要你完成了同调，直到以整轮动作解除同调之前，你可以将自身移动速度立刻提升至两倍音速（2288km/h）。当然，在这期间你因为维持高度集中而承受同调期间带来的一切效果（比如失去基础和闪避防御），也无法执行移动以外的任何行为，受到伤害时会自动解除同调。</p><p>失坠之踏技·铁枷<br> 价格：C+1000<br> 动作：整轮动作<br> 类型：攻击技<br> 消耗：1点通用能量/1意志力<br> 射程：触及<br> 范围：一个目标<br> 描述：由膝部以下出现外形有如巨大化的长刀的武器，坚硬无比。以重力加速度的形式贯穿敌手。<br> 效果：你以整轮动作进行一次空中冲锋攻击。在本次攻击中，武器威力提升会使武器伤害增加等同传奇决心*3L。<br> 你必须从位于对方之上的位置才能发起本次冲锋，此时计算高度差，每具有3米的高度，最终成功数就提升1点，上限为你的传奇决心</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',28)])])}const h=p(s,[["render",n]]);export{k as __pageData,h as default};
